      if (val) return truncate(toSingleLine(val));
    }
  }

  // 3. notes / description fallback
  return truncate(toSingleLine(fields.notes || fallback || ''));
}

for (const item of $input.all()) {
  // Handles: {status, data: [...]}, {data: [...]}, or a bare booking object
  const bookings = item.json.data ?? (Array.isArray(item.json) ? item.json : [item.json]);

  for (const b of bookings) {
    const attendee =
      b.attendees?.find((a) => a.phoneNumber) ||
      b.attendees?.find((a) => a.name) ||
      b.attendees?.[0] ||
      {};
    const fields = b.bookingFieldsResponses ?? {};
    const host = b.hosts?.[0] ?? {};
    const tz = attendee.timeZone || host.timeZone || 'Asia/Kolkata';
    const start = new Date(b.start);

    const meetingDate = new Intl.DateTimeFormat('en-IN', {
      timeZone: tz,
      day: 'numeric',
      month: 'long',
      year: 'numeric',
    }).format(start);
    const meetingTime = new Intl.DateTimeFormat('en-IN', {
      timeZone: tz,
      hour: 'numeric',
      minute: '2-digit',
      hour12: true,
    }).format(start);

    const rawPhone = attendee.phoneNumber || fields.attendeePhoneNumber || '';
    const phone = rawPhone.replace(/\D/g, '');

    const agenda = extractAgenda(fields, b.description);

    results.push({
      json: {
        bookingId: b.id,
        bookingUid: b.uid,
        status: b.status,
        customerName: attendee.name || fields.name || 'there',
        customerEmail: attendee.email || fields.email || '',
        customerPhone: phone,
        meetingTitle: b.title,
        eventTypeSlug: b.eventType?.slug || '',
        meetingDate,
        meetingTime,
        meetingLink: b.meetingUrl || b.location || '',
        timeZone: tz,
        startTimeISO: b.start,
        endTimeISO: b.end,
        durationMinutes: b.duration,
        agenda,
        hostName: host.name || '',
        hostEmail: host.email || '',
        guests: b.guests ?? [],
      },
    });
  }
}

return results;

// --- Config ---
const WINDOWS = [
  { label: '15_min', fromMin: 0,  toMin: 15 },
  { label: '60_min', fromMin: 58, toMin: 70 },
];
const VALID_STATUSES = ['accepted'];   // Cal.com: accepted | pending | cancelled | rejected
const DEFAULT_TZ = 'Asia/Kolkata';

// --- Helpers ---
const fmt = (d, tz, opts) => new Intl.DateTimeFormat('en-IN', { timeZone: tz, ...opts }).format(d);
const dayStr  = (d, tz) => fmt(d, tz, { weekday: 'long' });
const isoDate = (d, tz) =>
  fmt(d, tz, { year: 'numeric', month: '2-digit', day: '2-digit' }).split('/').reverse().join('-');
function humanDuration(totalMin) {
  const mins = Math.max(0, Math.round(totalMin));
  const h = Math.floor(mins / 60);
  const m = mins % 60;
  const parts = [];
  if (h) parts.push(`${h} hour${h > 1 ? 's' : ''}`);
  if (m) parts.push(`${m} minute${m > 1 ? 's' : ''}`);
  return parts.join(' ') || '0 minutes';
}

const now = Date.now();
const out = [];

for (const item of $input.all()) {
  const b = item.json;
  if (!VALID_STATUSES.includes(b.status)) continue;
  if (!b.startTimeISO) continue;
  const startMs = new Date(b.startTimeISO).getTime();
  if (Number.isNaN(startMs) || startMs <= now) continue;
  const minutesUntil = (startMs - now) / 60000;
  const win = WINDOWS.find(w => minutesUntil >= w.fromMin && minutesUntil < w.toMin);
  if (!win) continue;

  const tz = b.timeZone || DEFAULT_TZ;
  const startDate = new Date(startMs);
  const minsLeft = Math.round(minutesUntil);

  // --- Client-side date/time (attendee's own timezone) ---
  const meetingDateClient = b.meetingDate;   // already computed upstream in attendee's tz
  const meetingTimeClient = b.meetingTime;

  // --- India-side date/time (always Asia/Kolkata) ---
  const meetingDateIndia = fmt(startDate, DEFAULT_TZ, { day: 'numeric', month: 'long', year: 'numeric' });
  const meetingTimeIndia = fmt(startDate, DEFAULT_TZ, { hour: 'numeric', minute: '2-digit', hour12: true });

  const todayKey    = isoDate(new Date(now), tz);
  const tomorrowKey = isoDate(new Date(now + 86400000), tz);
  const eventKey    = isoDate(startDate, tz);
  const relativeDay =
    eventKey === todayKey ? 'Today'
    : eventKey === tomorrowKey ? 'Tomorrow'
    : dayStr(startDate, tz);

  const todayKeyIndia    = isoDate(new Date(now), DEFAULT_TZ);
  const tomorrowKeyIndia = isoDate(new Date(now + 86400000), DEFAULT_TZ);
  const eventKeyIndia    = isoDate(startDate, DEFAULT_TZ);
  const relativeDayIndia =
    eventKeyIndia === todayKeyIndia ? 'Today'
    : eventKeyIndia === tomorrowKeyIndia ? 'Tomorrow'
    : dayStr(startDate, DEFAULT_TZ);

  // Guests list repeats the customer's own email — drop it.
  const otherGuests = (b.guests || []).filter(
    g => g.toLowerCase() !== (b.customerEmail || '').toLowerCase()
  );

  out.push({
    json: {
      reminderType: win.label,
      bookingId: b.bookingId,
      bookingUid: b.bookingUid,
      eventTypeSlug: b.eventTypeSlug,
      title: b.meetingTitle,

      // --- Person ---
      customerName: b.customerName || null,
      customerEmail: b.customerEmail || null,
      customerPhone: b.customerPhone || null,
      hasPhone: Boolean(b.customerPhone),

      // --- Client tz ---
      meetingDateClient,
      meetingTimeClient,
      dayOfWeek: dayStr(startDate, tz),
      relativeDay,

      // --- India tz (always Asia/Kolkata) ---
      meetingDateIndia,
      meetingTimeIndia,
      dayOfWeekIndia: dayStr(startDate, DEFAULT_TZ),
      relativeDayIndia,

      durationFormatted: humanDuration(b.durationMinutes),
      startsInFormatted: humanDuration(minsLeft),       // "1 hour 2 minutes"

      // --- Raw, for logic downstream ---
      minutesUntil: minsLeft,
      durationMinutes: b.durationMinutes,
      startTimeISO: b.startTimeISO,
      endTimeISO: b.endTimeISO,
      eventDate: eventKey,
      eventDateIndia: eventKeyIndia,
      timeZone: tz,
      meetingLink: b.meetingLink || null,
      agenda: b.agenda || '',
      hostName: b.hostName,
      hostEmail: b.hostEmail,
      guests: otherGuests,
      dedupeKey: `${b.bookingUid}:${win.label}`,
    },
  });
}
return out;

