const targetPackageIds = $('Limit1').first().json.not_allow_packages_ids;

const bookingItems = $('refine data ').all();

const rawUserItems = $('HTTP Request').all();
let userList = [];
for (const it of rawUserItems) {
  const j = it.json;
  if (Array.isArray(j)) {
    userList.push(...j);
  } else if (j && Array.isArray(j.message)) {
    userList.push(...j.message);   // ← your API's actual wrapper key
  } else if (j && Array.isArray(j.data)) {
    userList.push(...j.data);
  } else if (j) {
    userList.push(j);
  }
}

const results = [];

for (const item of bookingItems) {
  const bookingData = item.json;
  const customerEmail = (bookingData.customerEmail || '').trim().toLowerCase();

  const matchedUser = userList.find(
    (u) => u.email && u.email.trim().toLowerCase() === customerEmail
  );

  let shouldCancel = true;
  let isExistingCustomer = !!matchedUser;

  if (matchedUser) {
    shouldCancel = targetPackageIds.includes(Number(matchedUser.package_id));
  }

  results.push({
    json: {
      ...bookingData,
      isExistingCustomer,
      matchedPackageId: matchedUser ? matchedUser.package_id : null,
      matchedPackageName: matchedUser ? matchedUser.package_name : null,
      shouldCancel,
      debug_totalUsersLoaded: userList.length, // keep for one more test, then remove
    },
  });
}

return results;

