  const bookingData = item.json;
  const customerEmail = (bookingData.customerEmail || '').trim().toLowerCase();

  const matchedUser = userList.find(
    (u) => u.email && u.email.trim().toLowerCase() === customerEmail
  );

  let shouldCancel = true;
  let isExistingCustomer = !!matchedUser;

  if (matchedUser) {
    shouldCancel = targetPackageIds.includes(Number(matchedUser.package_id));
  }

  results.push({
    json: {
      ...bookingData,
      isExistingCustomer,
      matchedPackageId: matchedUser ? matchedUser.package_id : null,
      matchedPackageName: matchedUser ? matchedUser.package_name : null,
      shouldCancel,
      debug_totalUsersLoaded: userList.length, // keep for one more test, then remove
    },
  });
}

return results;

const results = [];

// Add any other field-label variants you use across event types here.
const AGENDA_FIELD_KEYS = [
  'What-you-expect-out-of-call', // used on Book-a-Demo, Partner, etc.
  'Call-Agenda',                  // used on other event types
];

const AGENDA_MAX_LENGTH = 300;

// Collapses newlines/extra whitespace into a single clean line
function toSingleLine(str) {
  if (!str) return '';
  return String(str)
    .replace(/\r?\n+/g, '. ')   // newline -> ". "
    .replace(/\.\.\s*/g, '. ')  // avoid double periods if line already ended with "."
    .replace(/\s{2,}/g, ' ')    // collapse extra spaces
    .trim();
}

// Truncates to max length without cutting a word in half
function truncate(str, maxLength = AGENDA_MAX_LENGTH) {
  if (!str || str.length <= maxLength) return str;
  const cut = str.slice(0, maxLength);
  const lastSpace = cut.lastIndexOf(' ');
  return (lastSpace > 0 ? cut.slice(0, lastSpace) : cut).trim() + '...';
}

function extractAgenda(payload) {
  const fields = payload.userFieldsResponses || {};

  // 1. Check known field keys in priority order, take the first one with a value
  for (const key of AGENDA_FIELD_KEYS) {
    const val = fields[key]?.value;
    if (val) return truncate(toSingleLine(val));
  }

  // 2. Fallback: scan any remaining userFieldsResponses whose label/key
  //    looks like an agenda field (covers future/typo'd variants)
  for (const key of Object.keys(fields)) {
    const label = (fields[key]?.label || key).toLowerCase();
    if (label.includes('agenda') || label.includes('expect')) {
      const val = fields[key]?.value;
      if (val) return truncate(toSingleLine(val));
    }
  }

  // 3. Final fallback
  return truncate(toSingleLine(payload.additionalNotes)) || '';
}

for (const item of $('Webhook').all()) {
  // Webhook data can arrive nested under `body` or flat
  const payload = item.json.body?.payload ?? item.json.payload;
  const attendee = payload.attendees?.[0] ?? {};
  const tz = attendee.timeZone || payload.organizer?.timeZone || 'Asia/Kolkata';
  const start = new Date(payload.startTime);
  const eventID = payload.eventTypeId;

  // --- Client-side date/time (attendee's own timezone) ---
  const meetingDateClient = new Intl.DateTimeFormat('en-IN', {
    timeZone: tz,
    day: 'numeric',
    month: 'long',
    year: 'numeric',
  }).format(start);
  const meetingTimeClient = new Intl.DateTimeFormat('en-IN', {
    timeZone: tz,
    hour: 'numeric',
    minute: '2-digit',
    hour12: true,
  }).format(start);

  // --- India-side date/time (always Asia/Kolkata, no matter who booked) ---
  const meetingDateIndia = new Intl.DateTimeFormat('en-IN', {
    timeZone: 'Asia/Kolkata',
    day: 'numeric',
    month: 'long',
    year: 'numeric',
  }).format(start);
  const meetingTimeIndia = new Intl.DateTimeFormat('en-IN', {
    timeZone: 'Asia/Kolkata',
    hour: 'numeric',
    minute: '2-digit',
    hour12: true,
  }).format(start);

  const meetingLink =
    payload.videoCallData?.url ||
    payload.metadata?.videoCallUrl ||
    payload.location ||
    '';

  // Booking management links — strip any trailing slash on bookerUrl
  const bookerUrl = (payload.bookerUrl || 'https://cal.com').replace(/\/+$/, '');
  const uid = payload.uid;
  const rescheduleLink =
    uid && !payload.disableRescheduling ? `${bookerUrl}/reschedule/${uid}` : '';
  const cancelLink =
    uid && !payload.disableCancelling ? `${bookerUrl}/booking/${uid}?cancel=true` : '';

  // WhatsApp API wants digits only, no "+"
  const rawPhone = attendee.phoneNumber || payload.responses?.attendeePhoneNumber?.value || '';
  const phone = rawPhone.replace(/\D/g, '');

  results.push({
    json: {
      triggerEvent: item.json.body?.triggerEvent ?? item.json.triggerEvent,
      bookingId: payload.bookingId,
      bookingUid: uid,
      status: payload.status,
      customerName: attendee.firstName || attendee.name || 'there',
      customerEmail: attendee.email || '',
      customerPhone: phone,
      meetingTitle: payload.eventTypeTitle || payload.title,
      // Client-facing (their local time — e.g. UK guest sees UK time)
      meetingDateClient,
      meetingTimeClient,
      // Internal / India-facing (always IST, e.g. for your own WhatsApp reminders)
      meetingDateIndia,
      meetingTimeIndia,
      eventID,
      meetingLink,
      rescheduleLink,
      cancelLink,
      bookingLink: uid ? `${bookerUrl}/booking/${uid}` : '',
      timeZone: tz,
      startTimeISO: payload.startTime,
      endTimeISO: payload.endTime,
      durationMinutes: payload.length,
      agenda: extractAgenda(payload),
    },
  });
}

return results;

